'use client'

import { useState } from 'react'

interface ContactFormProps {
  onSubmit: (data: { name: string; phone: string; email: string }) => Promise<void>
}

export default function ContactForm({ onSubmit }: ContactFormProps) {
  const [formData, setFormData] = useState({ name: '', phone: '', email: '' })
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [isSubmitted, setIsSubmitted] = useState(false)

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  const phoneRegex = /^(\+1\s?)?(\(\d{3}\)\s?|\d{3}-?)\d{3}-?\d{4}$/

  const isEmailValid = emailRegex.test(formData.email)
  const isPhoneValid = phoneRegex.test('+1' + formData.phone)
  const isNameValid = formData.name.trim().length > 0
  const isFormValid = isNameValid && isEmailValid && isPhoneValid

  const handleInputChange = (field: keyof typeof formData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }))
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!isFormValid || isSubmitting) return

    setIsSubmitting(true)
    try {
      await onSubmit({
        name: formData.name.trim(),
        phone: '+1' + formData.phone,
        email: formData.email.trim(),
      })
      setIsSubmitted(true)
    } catch (error) {
      console.error('Error submitting form:', error)
    } finally {
      setIsSubmitting(false)
    }
  }

  const inputClass = (hasError: boolean) =>
    `w-full bg-transparent border-0 border-b pb-2 font-light text-sm text-foreground/85 placeholder:text-foreground/25 outline-none transition-colors duration-300 ${
      hasError ? 'border-red-400/50 focus:border-red-400/70' : 'border-white/18 focus:border-primary/45'
    }`

  if (isSubmitted) {
    return (
      <div className="py-4">
        <p className="label-caps flex items-center gap-2">
          <span className="inline-block w-1.5 h-1.5 rounded-full bg-emerald-400 flex-shrink-0" />
          <span className="text-emerald-400/80">Information received — a representative will contact you shortly.</span>
        </p>
      </div>
    )
  }

  return (
    <div className="w-full max-w-sm py-2">
      <p className="label-caps text-foreground/35 mb-6">Contact Information</p>
      <form onSubmit={handleSubmit} className="space-y-6">

        <div>
          <label htmlFor="name" className="label-caps text-foreground/35 block mb-3">Name</label>
          <input
            id="name"
            type="text"
            value={formData.name}
            onChange={(e) => handleInputChange('name', e.target.value)}
            placeholder="Full name"
            className={inputClass(!isNameValid && !!formData.name)}
            disabled={isSubmitting}
          />
        </div>

        <div>
          <label htmlFor="phone" className="label-caps text-foreground/35 block mb-3">Phone</label>
          <div className="flex items-end gap-2">
            <span className="label-caps text-foreground/30 pb-2 border-b border-white/18 flex-shrink-0">+1</span>
            <input
              id="phone"
              type="tel"
              value={formData.phone}
              onChange={(e) => handleInputChange('phone', e.target.value)}
              placeholder="(555) 123-4567"
              className={`flex-1 bg-transparent border-0 border-b pb-2 font-light text-sm text-foreground/85 placeholder:text-foreground/25 outline-none transition-colors duration-300 ${
                !isPhoneValid && formData.phone ? 'border-red-400/50 focus:border-red-400/70' : 'border-white/18 focus:border-primary/45'
              }`}
              disabled={isSubmitting}
            />
          </div>
          {formData.phone && !isPhoneValid && (
            <p className="label-caps text-red-400/70 mt-2">Enter a valid US phone number</p>
          )}
        </div>

        <div>
          <label htmlFor="email" className="label-caps text-foreground/35 block mb-3">Email</label>
          <input
            id="email"
            type="email"
            value={formData.email}
            onChange={(e) => handleInputChange('email', e.target.value)}
            placeholder="your@email.com"
            className={inputClass(!isEmailValid && !!formData.email)}
            disabled={isSubmitting}
          />
          {formData.email && !isEmailValid && (
            <p className="label-caps text-red-400/70 mt-2">Enter a valid email address</p>
          )}
        </div>

        <button
          type="submit"
          disabled={!isFormValid || isSubmitting}
          className="label-caps text-primary hover:text-foreground/80 transition-colors duration-300 disabled:opacity-30 disabled:cursor-not-allowed flex items-center gap-2 pt-1"
        >
          {isSubmitting ? (
            <>
              <span className="inline-block w-3 h-3 border border-primary border-t-transparent rounded-full animate-spin" />
              Submitting
            </>
          ) : (
            'Submit →'
          )}
        </button>
      </form>
    </div>
  )
}
