'use client'

import { useState, useRef } from 'react'
import Image from 'next/image'
import ChatAnalyticsChart from '@/components/ChatAnalyticsChart'

interface AdminDashboardProps {
  onBack: () => void
}

export default function AdminDashboard({ onBack }: AdminDashboardProps) {
  const fileInputRef = useRef<HTMLInputElement>(null)
  const [selectedFile, setSelectedFile] = useState<File | null>(null)
  const [isUploading, setIsUploading] = useState(false)
  const [uploadStatus, setUploadStatus] = useState<{ message: string; success: boolean } | null>(null)

  const handleUpload = async () => {
    if (!selectedFile) return

    setIsUploading(true)
    setUploadStatus(null)

    const formData = new FormData()
    formData.append('file', selectedFile)

    try {
      const response = await fetch('/api/admin/upload-hotel-info', {
        method: 'POST',
        body: formData,
      })

      const result = await response.json()

      if (response.ok) {
        setUploadStatus({ message: 'File uploaded successfully', success: true })
        setSelectedFile(null)
        if (fileInputRef.current) fileInputRef.current.value = ''
      } else {
        setUploadStatus({ message: result.error || 'Upload failed', success: false })
      }
    } catch (error) {
      console.error('Upload error:', error)
      setUploadStatus({ message: 'Upload failed. Please try again.', success: false })
    } finally {
      setIsUploading(false)
    }
  }

  return (
    <div className="min-h-screen relative">
      {/* Background */}
      <div className="absolute inset-0 z-0">
        <Image
          src="/background.jpg"
          alt="The Cincinnatian Hotel"
          fill
          className="object-cover"
          priority
          quality={90}
        />
        <div className="absolute inset-0 bg-black/65" />
      </div>

      <div className="relative z-10 flex flex-col min-h-screen">
        {/* Header */}
        <header className="flex items-center justify-between px-8 sm:px-12 py-5 backdrop-blur-md bg-black/20 border-b border-white/8 sticky top-0 z-50">
          <div className="flex items-center gap-3">
            <Image
              src="/hotel-logo.png"
              alt="The Cincinnatian Hotel"
              width={22}
              height={22}
              className="opacity-70"
            />
            <span className="label-caps text-foreground/55">The Cincinnatian</span>
          </div>
          <button
            onClick={onBack}
            className="label-caps text-foreground/35 hover:text-foreground/65 transition-colors duration-300"
          >
            ← Exit
          </button>
        </header>

        {/* Main content */}
        <main className="flex-1 max-w-4xl mx-auto w-full px-8 sm:px-12 py-12 sm:py-16 space-y-16">

          {/* Upload section */}
          <section>
            <div className="mb-8">
              <p className="label-caps text-foreground/40 mb-2">Document Management</p>
              <h2 className="text-2xl font-light text-foreground">Hotel Information</h2>
            </div>

            <p className="text-foreground/50 font-light text-sm mb-8 max-w-lg">
              Upload a PDF containing your hotel's information. This serves as the knowledge base for the AI concierge. A new upload replaces the previous file.
            </p>

            <input
              type="file"
              accept=".pdf"
              ref={fileInputRef}
              className="hidden"
              onChange={(e) => {
                if (e.target.files && e.target.files[0]) {
                  setSelectedFile(e.target.files[0])
                  setUploadStatus(null)
                }
              }}
            />

            {/* Upload zone */}
            <div
              onClick={() => fileInputRef.current?.click()}
              className="border border-white/12 rounded-2xl p-10 sm:p-14 text-center hover:border-primary/30 hover:bg-white/[0.015] transition-all duration-500 cursor-pointer max-w-lg"
            >
              <p className="label-caps text-foreground/35 mb-4">PDF only · Max 50 MB</p>
              {selectedFile ? (
                <p className="text-primary font-light text-sm">{selectedFile.name}</p>
              ) : (
                <p className="text-foreground/45 font-light text-sm">Drag here or click to browse</p>
              )}
            </div>

            {/* Actions */}
            {selectedFile && (
              <div className="mt-6 flex items-center gap-6">
                <button
                  onClick={handleUpload}
                  disabled={isUploading}
                  className="label-caps text-primary hover:text-foreground/80 transition-colors duration-300 disabled:opacity-30 disabled:cursor-not-allowed flex items-center gap-2"
                >
                  {isUploading ? (
                    <>
                      <span className="inline-block w-3 h-3 border border-primary border-t-transparent rounded-full animate-spin" />
                      Uploading
                    </>
                  ) : (
                    'Upload →'
                  )}
                </button>
                <button
                  onClick={() => {
                    setSelectedFile(null)
                    if (fileInputRef.current) fileInputRef.current.value = ''
                  }}
                  disabled={isUploading}
                  className="label-caps text-foreground/30 hover:text-foreground/55 transition-colors duration-300 disabled:opacity-30"
                >
                  Clear
                </button>
              </div>
            )}

            {/* Status indicator */}
            {uploadStatus && (
              <p className="label-caps mt-5 flex items-center gap-2">
                <span className={`inline-block w-1.5 h-1.5 rounded-full flex-shrink-0 ${uploadStatus.success ? 'bg-emerald-400' : 'bg-red-400'}`} />
                <span className={uploadStatus.success ? 'text-emerald-400/80' : 'text-red-400/80'}>
                  {uploadStatus.message}
                </span>
              </p>
            )}
          </section>

          {/* Analytics section */}
          <section>
            <div className="mb-8">
              <p className="label-caps text-foreground/40 mb-2">Insights</p>
              <h2 className="text-2xl font-light text-foreground">Chat Statistics</h2>
            </div>
            <ChatAnalyticsChart />
          </section>

        </main>
      </div>
    </div>
  )
}
